def solve(tickets):
    import collections
    adj = collections.defaultdict(list)
    for f, t in sorted(tickets)[::-1]:
        adj[f].append(t)
    res = []
    def dfs(node):
        while adj[node]:
            dfs(adj[node].pop())
        res.append(node)
    dfs('JFK')
    return str(res[::-1]).replace("'", '"')

